    50→func (s *Service) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
    51→	if req == nil {
    52→		return nil, errNilRequest
    53→	}
    54→
    55→	p, exists := s.plugin(ctx, req.PluginContext.PluginID, req.PluginContext.PluginVersion)
    56→	if !exists {
    57→		return nil, plugins.ErrPluginNotRegistered
    58→	}
    59→
    60→	resp, err := p.QueryData(ctx, req)
    61→	if err != nil {
    62→		for _, e := range passthroughErrors {
    63→			if errors.Is(err, e) {
    64→				return nil, err
    65→			}
    66→		}
    67→
    68→		// If the error is a plugin grpc connection unavailable error, return it directly
    69→		// This error is created dynamically based on the context, so we need to check for it here
    70→		if errors.Is(err, plugins.ErrPluginGrpcConnectionUnavailableBaseFn(ctx)) {
    71→			return nil, err
    72→		}
    73→
    74→		if errors.Is(err, context.Canceled) {
    75→			return nil, plugins.ErrPluginRequestCanceledErrorBase.Errorf("client: query data request canceled: %w", err)
    76→		}
    77→
    78→		if s, ok := grpcstatus.FromError(err); ok && s.Code() == grpccodes.Canceled {
    79→			return nil, plugins.ErrPluginRequestCanceledErrorBase.Errorf("client: query data request canceled: %w", err)
    80→		}
    81→
    82→		return nil, plugins.ErrPluginRequestFailureErrorBase.Errorf("client: failed to query data: %w", err)
    83→	}
    84→
    85→	for refID, res := range resp.Responses {
    86→		// set frame ref ID based on response ref ID
    87→		for _, f := range res.Frames {
    88→			if f.RefID == "" {
    89→				f.RefID = refID
    90→			}
    91→		}
    92→	}
    93→
    94→	return resp, err
    95→}
